        LinearLayout tools=row();Button sources=button("SOURCE /\nMATERIAL LISTS");Button letterhead=button("EDIT COMPANY\nHEADER");for(Button b:new Button[]{sources,letterhead}){b.setTextSize(11);b.setMaxLines(2);b.setTypeface(Typeface.DEFAULT_BOLD);b.setTextColor(Color.rgb(91,41,145));}tools.addView(sources,weighted(1.15f,54));tools.addView(letterhead,weighted(1f,54));page.addView(tools);sources.setOnClickListener(v->showSourceManager());letterhead.setOnClickListener(v->showLetterheadSettings());

        Button camera=button("CAMERA • AI READ MATERIAL LIST");camera.setTypeface(Typeface.DEFAULT_BOLD);camera.setTextColor(Color.WHITE);camera.setBackground(rounded(Color.rgb(0,125,93),14));LinearLayout.LayoutParams cameraLp=new LinearLayout.LayoutParams(-1,dp(48));cameraLp.setMargins(dp(2),dp(3),dp(2),dp(5));page.addView(camera,cameraLp);camera.setOnClickListener(v->captureMaterialList());

        customerSummary=text("",14,Color.DKGRAY,false);customerSummary.setPadding(dp(12),dp(8),dp(12),dp(8));customerSummary.setBackground(rounded(Color.WHITE,14));page.addView(customerSummary,new LinearLayout.LayoutParams(-1,dp(62)));customerSummary.setOnClickListener(v->showCustomerDetails());

        LinearLayout quoteTools=row();Button add=button("+ ADD MATERIAL ITEM");Button discounts=button("DISCOUNT STRUCTURE");add.setTypeface(Typeface.DEFAULT_BOLD);add.setTextColor(Color.rgb(0,110,70));discounts.setTypeface(Typeface.DEFAULT_BOLD);discounts.setTextColor(Color.rgb(170,95,0));quoteTools.addView(add,weighted(1.2f,48));quoteTools.addView(discounts,weighted(1f,48));page.addView(quoteTools);add.setOnClickListener(v->showAddItemOptions());discounts.setOnClickListener(v->showDiscountSettings());

        quoteSummary=text("",13,Color.DKGRAY,true);quoteSummary.setPadding(dp(7),dp(4),dp(7),dp(4));quoteSummary.setMaxLines(2);page.addView(quoteSummary,new LinearLayout.LayoutParams(-1,dp(54)));
