        LinearLayout outputs=row();outputs.setPadding(0,dp(4),0,dp(4));Button preview=button("PREVIEW");Button image=button("SHARE\nIMAGE");Button pdf=button("SHARE\nPDF");for(Button b:new Button[]{preview,image,pdf}){b.setTextSize(11);b.setMaxLines(2);b.setTypeface(Typeface.DEFAULT_BOLD);b.setTextColor(Color.WHITE);}preview.setBackground(rounded(Color.rgb(91,41,145),14));image.setBackground(rounded(Color.rgb(23,112,155),14));pdf.setBackground(rounded(Color.rgb(190,45,45),14));outputs.addView(preview,weighted(.8f,58));outputs.addView(image,weighted(1f,58));outputs.addView(pdf,weighted(1f,58));page.addView(outputs,new LinearLayout.LayoutParams(-1,dp(66)));preview.setOnClickListener(v->showPreview());image.setOnClickListener(v->shareQuoteImage());pdf.setOnClickListener(v->shareQuotePdf());
